import React, { useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { resolveUnitDisplay, formatRent, safeFloat } from '../../../utils/formatters';

const UpcomingEscalations = ({ leases = [], parties = [], loading }) => {
  const navigate = useNavigate();

  // Build party lookup map from Masters — brand_name or company_name by party id
  const partiesMap = useMemo(() => {
    const map = {};
    parties.forEach(p => { map[p.id] = p; });
    return map;
  }, [parties]);

  const handleLeaseClick = (leaseId) => {
    navigate(`/admin/view-lease/${leaseId}`);
  };

  const getEscalationColor = (days) => {
    if (days <= 30) return { bg: '#fee2e2', text: '#991b1b', status: 'Critical' };
    if (days <= 90) return { bg: '#dbeafe', text: '#1d4ed8', status: 'Secure' };
    return { bg: '#dcfce7', text: '#166534', status: 'Active' };
  };

  const escalationData = useMemo(() => {
    if (!leases || leases.length === 0) return [];

    const now = new Date();
    const escalations = [];

    const activeLeases = leases.filter(lease => {
      const status = (lease.status || '').toLowerCase().trim();
      return ['active', 'approved', 'executed', 'registered', 'occupied'].includes(status);
    });

    activeLeases.forEach(lease => {
      const leaseEscalations = Array.isArray(lease.escalations) ? lease.escalations : [];

      // Resolve unit number — top-level field from backend
      const unitNumber = resolveUnitDisplay(lease);
      // Resolve brand name: use Masters partiesMap first (guaranteed), then lease fields
      const party = partiesMap[lease.party_tenant_id];
      const displayName =
        (party?.brand_name && party.brand_name.trim()) ||
        (party?.company_name && party.company_name.trim()) ||
        (lease.tenant?.brand_name && String(lease.tenant.brand_name).trim()) ||
        (lease.brand_name && String(lease.brand_name).trim()) ||
        (lease.tenant?.company_name && String(lease.tenant.company_name).trim()) ||
        (lease.tenant_name && String(lease.tenant_name).trim()) ||
        `${lease.tenant?.first_name || ''} ${lease.tenant?.last_name || ''}`.trim() ||
        '-';
      const projectLabel = lease.project_name || '';
      const area = safeFloat(lease.chargeable_area || lease.area_leased || lease.units?.chargeable_area || 0);
      const currentRent = safeFloat(lease.monthly_rent || 0);

      if (leaseEscalations.length > 0) {
        const upcomingEsc = leaseEscalations
          .filter(e => e.effective_from && new Date(e.effective_from) > now)
          .sort((a, b) => new Date(a.effective_from) - new Date(b.effective_from))[0];

        if (upcomingEsc) {
          const escDate = new Date(upcomingEsc.effective_from);
          const daysDiff = Math.ceil((escDate - now) / (1000 * 60 * 60 * 24));

          let newRent = currentRent;
          if (upcomingEsc.increase_type === 'Percentage' && upcomingEsc.value) {
            newRent = currentRent * (1 + parseFloat(upcomingEsc.value) / 100);
          } else if (upcomingEsc.increase_type === 'Fixed' && upcomingEsc.value) {
            newRent = currentRent + parseFloat(upcomingEsc.value);
          } else if (upcomingEsc.rate_per_sqft) {
            newRent = parseFloat(upcomingEsc.rate_per_sqft) * area;
          }

          if (daysDiff > 0) {
            escalations.push({
              leaseId: lease.id,
              unitNumber: unitNumber || '-',
              displayName,
              projectLabel,
              area,
              currentRent,
              newRent,
              days: daysDiff,
              escalationDate: escDate,
              increaseType: upcomingEsc.increase_type,
              increaseValue: upcomingEsc.value,
            });
          }
        }
      }
    });

    return escalations.sort((a, b) => a.days - b.days);
  }, [leases, partiesMap]);

  return (
    <div className="echo-card" style={{ border: 'none' }}>
      <h3 style={{ fontSize: '14px', fontWeight: 600, color: '#0f172a', marginBottom: '2px' }}>Upcoming Escalations</h3>
      <p style={{ fontSize: '12px', color: '#64748b', marginBottom: '16px' }}>Rent escalation status · Sorted by urgency</p>

      {loading ? (
        <div style={{ textAlign: 'center', padding: '20px', color: '#64748b' }}>Loading...</div>
      ) : escalationData.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '20px', color: '#64748b' }}>No upcoming escalations found</div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '14px', maxHeight: '300px', overflowY: 'auto', paddingRight: '8px' }}>
          {escalationData.slice(0, 5).map((esc, i) => {
            const colorInfo = getEscalationColor(esc.days);
            return (
              <div
                key={i}
                onClick={() => handleLeaseClick(esc.leaseId)}
                style={{
                  display: 'flex', alignItems: 'center', gap: '12px',
                  cursor: 'pointer', padding: '8px 10px', borderRadius: '8px',
                  transition: 'background-color 0.15s', border: '1px solid transparent'
                }}
                onMouseEnter={(e) => { e.currentTarget.style.backgroundColor = '#f8fafc'; e.currentTarget.style.borderColor = '#e2e8f0'; }}
                onMouseLeave={(e) => { e.currentTarget.style.backgroundColor = 'transparent'; e.currentTarget.style.borderColor = 'transparent'; }}
              >
                {/* Unit number badge */}
                <div style={{
                  minWidth: '68px', background: '#eff6ff', borderRadius: '6px',
                  padding: '4px 6px', textAlign: 'center'
                }}>
                  <span style={{ fontSize: '12px', fontWeight: 700, color: '#1d4ed8' }}>{esc.unitNumber}</span>
                </div>

                {/* Name + rent change */}
                <div style={{ flex: 1, minWidth: 0 }}>
                  <p style={{ fontSize: '13px', color: '#0f172a', margin: 0, fontWeight: 600, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{esc.displayName}</p>
                  <p style={{ fontSize: '11px', color: '#94a3b8', margin: 0 }}>
                    {formatRent(esc.currentRent)} <span style={{ color: '#0ea5e9' }}>→</span> {formatRent(esc.newRent)} PM
                  </p>
                </div>

                {/* Days + status */}
                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: '4px', flexShrink: 0 }}>
                  <span style={{ fontSize: '13px', fontWeight: 600, color: colorInfo.text }}>{esc.days}d</span>
                  <span style={{
                    fontSize: '11px', padding: '2px 8px', borderRadius: '9999px',
                    fontWeight: 500, backgroundColor: colorInfo.bg, color: colorInfo.text
                  }}>{colorInfo.status}</span>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default UpcomingEscalations;
